// Normalize Vapi and Retell webhook payloads into a unified structure
const items = $input.all();
const body = items[0].json.body || items[0].json;

let call_id, phone_number, transcript, recording_url, duration_sec, provider;

// Detect Vapi format
if (body.message && (body.message.type === 'end-of-call-report' || body.message.type === 'end-of-call')) {
  provider = 'vapi';
  const msg = body.message;
  call_id = (msg.call && msg.call.id) || msg.callId || 'unknown';
  phone_number = (msg.call && msg.call.customer && msg.call.customer.number) || msg.customerNumber || '';
  transcript = msg.transcript || msg.artifactTranscript || '';
  recording_url = msg.recordingUrl || (msg.artifact && msg.artifact.recordingUrl) || '';
  duration_sec = (msg.call && msg.call.duration) || msg.duration || 0;

// Detect Retell format
} else if (body.event === 'call_ended' || body.event === 'call_analyzed') {
  provider = 'retell';
  const data = body.data || body;
  call_id = data.call_id || data.callId || 'unknown';
  phone_number = data.from_number || data.fromNumber || data.customer_number || '';
  // Retell transcript may be an array of turn objects
  if (Array.isArray(data.transcript)) {
    transcript = data.transcript.map(t => `${t.role || t.speaker}: ${t.content || t.text}`).join('\n');
  } else {
    transcript = data.transcript || '';
  }
  recording_url = data.recording_url || data.recordingUrl || '';
  duration_sec = data.duration_sec || (data.duration_ms ? Math.round(data.duration_ms / 1000) : 0);

// Fallback / generic format
} else {
  provider = 'unknown';
  call_id = body.call_id || body.callId || 'unknown-' + Date.now();
  phone_number = body.phone_number || body.from || body.customer_number || '';
  transcript = body.transcript || '';
  recording_url = body.recording_url || '';
  duration_sec = body.duration_sec || body.duration || 0;
}

// Normalize phone to E.164
if (phone_number && !phone_number.startsWith('+')) {
  const digits = phone_number.replace(/\D/g, '');
  phone_number = digits.length === 10 ? '+1' + digits : '+' + digits;
}

return [{
  json: {
    call_id,
    phone_number,
    transcript,
    recording_url,
    duration_sec: parseInt(duration_sec) || 0,
    provider,
    raw_body: body
  }
}];

