parameters.jsCode:
const items = $input.all();
const item = items[0];

// The AI Agent output is in item.json.output (string) or already parsed object
let bant;
try {
  const raw = item.json.output || item.json;
  if (typeof raw === 'string') {
    const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    bant = JSON.parse(cleaned);
  } else if (typeof raw === 'object' && raw.score !== undefined) {
    bant = raw;
  } else if (raw.output && typeof raw.output === 'object') {
    bant = raw.output;
  } else {
    bant = { score: 0, budget_confirmed: false, authority_confirmed: false, need_identified: false, timeline_defined: false, summary: 'Parse error', key_objections: [] };
  }
} catch(e) {
  bant = { score: 0, budget_confirmed: false, authority_confirmed: false, need_identified: false, timeline_defined: false, summary: 'Parse error: ' + e.message, key_objections: [] };
}

return [{
  json: {
    ...item.json,
    bant_score: bant.score || 0,
    budget_confirmed: bant.budget_confirmed || false,
    authority_confirmed: bant.authority_confirmed || false,
    need_identified: bant.need_identified || false,
    timeline_defined: bant.timeline_defined || false,
    bant_summary: bant.summary || '',
    key_objections: bant.key_objections || [],
    qualified: (bant.score || 0) >= 6
  }
}];

