parameters.jsCode:
const items = $input.all();
const item = items[0];

let ranked;
try {
  const raw = item.json.output || item.json;
  if (typeof raw === 'string') {
    const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    ranked = JSON.parse(cleaned);
  } else if (typeof raw === 'object' && raw.ranked_leads) {
    ranked = raw;
  } else if (raw.output && typeof raw.output === 'object') {
    ranked = raw.output;
  } else {
    ranked = { ranked_leads: [] };
  }
} catch(e) {
  ranked = { ranked_leads: [] };
}

// Sort descending by priority_score, filter for valid phone numbers, limit 50
const leads = (ranked.ranked_leads || [])
  .sort((a, b) => (b.priority_score || 0) - (a.priority_score || 0))
  .filter(l => l.phone && l.phone.trim() !== '' && l.phone !== 'undefined')
  .slice(0, 50);

if (leads.length === 0) {
  return [{ json: { skip: true, message: 'No leads with phone numbers to call today.' } }];
}

// Return each lead as a separate item for batch processing
return leads.map(lead => ({ json: lead }));
